543	// authorizeTransition checks if the current user is allowed to perform the transition.
544	func (h *Handler) authorizeTransition(c *gin.Context, wo *WorkOrder, toStatus string, userID uint64, roles []string) *common.AppError {
545		_ = c // included for consistency; roles/userID already extracted
546	
547		// SystemAdmin can do anything.
548		if hasRole(roles, common.RoleSystemAdmin) {
549			return nil
550		}
551	
552		// PropertyManager can approve/reject (AwaitingApproval -> Completed or InProgress) and archive,
553		// but only for work orders on properties they manage.
554		if hasRole(roles, common.RolePropertyManager) {
555			managed, err := h.service.IsManagedBy(wo.PropertyID, userID)
556			if err != nil || !managed {
557				return common.NewForbiddenError("you do not manage the property for this work order")
558			}
559			return nil
560		}
561	
562		// Technician can transition their own assigned work orders (Assigned->InProgress, InProgress->AwaitingApproval).
563		if hasRole(roles, common.RoleTechnician) {
564			if wo.AssignedTo == nil || *wo.AssignedTo != userID {
565				return common.NewForbiddenError("you can only transition work orders assigned to you")
566			}
567			if toStatus == common.WOStatusInProgress || toStatus == common.WOStatusAwaitingApproval {
568				return nil
569			}
570			return common.NewForbiddenError("technicians can only move to InProgress or AwaitingApproval")
571		}
572	
573		return common.NewForbiddenError("insufficient permissions for this transition")
574	}
