188	// --- Quality metrics tests ---
189	
190	// TestQualityMetrics_NegativeRate verifies the negative-rate calculation.
191	// Ratings: [5, 1, 2] → 3 rated, 2 negative (<=2), rate = 2/3.
192	func TestQualityMetrics_NegativeRate(t *testing.T) {
193		ratings := []uint8{5, 1, 2}
194	
195		var total, negative int64
196		var sum float64
197		for _, r := range ratings {
198			total++
199			sum += float64(r)
200			if r <= 2 {
201				negative++
202			}
203		}
204	
205		q := &QualityMetric{
206			TotalRated:    total,
207			AverageRating: sum / float64(total),
208			NegativeCount: negative,
209		}
210		if total > 0 {
211			q.NegativeRate = float64(negative) / float64(total)
212		}
213	
214		if q.TotalRated != 3 {
215			t.Errorf("TotalRated: want 3, got %d", q.TotalRated)
216		}
217		if q.NegativeCount != 2 {
218			t.Errorf("NegativeCount: want 2, got %d", q.NegativeCount)
219		}
220	
221		wantRate := 2.0 / 3.0
222		if diff := q.NegativeRate - wantRate; diff > 0.001 || diff < -0.001 {
223			t.Errorf("NegativeRate: want %.4f, got %.4f", wantRate, q.NegativeRate)
224		}
225	
226		wantAvg := (5.0 + 1.0 + 2.0) / 3.0
227		if diff := q.AverageRating - wantAvg; diff > 0.001 || diff < -0.001 {
228			t.Errorf("AverageRating: want %.4f, got %.4f", wantAvg, q.AverageRating)
229		}
230	}
