89	// validScheduleValues enumerates the schedule strings accepted by the report
90	// scheduler. The only supported value is "daily"; any other non-empty string
91	// is rejected to prevent silent no-op scheduled reports.
92	var validScheduleValues = map[string]bool{
93		"":      true, // empty = no schedule (on-demand only)
