97	// CreateSavedReport persists a new SavedReport.
98	func (s *Service) CreateSavedReport(req SavedReportRequest, ownerID uint64) (*SavedReport, *common.AppError) {
99		if !validScheduleValues[req.Schedule] {
100			return nil, common.NewValidationError("schedule must be 'daily' or empty (on-demand only)")
101		}
102	
103		format := req.OutputFormat
104		if format == "" {
105			format = "CSV"
106		}
107	
108		var filtersJSON []byte
109		if req.Filters != nil {
110			b, err := json.Marshal(req.Filters)
111			if err != nil {
112				return nil, common.NewInternalError("failed to encode filters")
113			}
114			filtersJSON = b
115		}
116	
117		report := &SavedReport{
118			UUID:         uuid.New().String(),
119			Name:         req.Name,
120			ReportType:   req.ReportType,
121			Filters:      filtersJSON,
122			OutputFormat: format,
123			Schedule:     req.Schedule,
124			OwnerID:      ownerID,
125			IsActive:     true,
