170	// GenerateReport runs a saved report and persists the file.
171	func (s *Service) GenerateReport(savedReportID uint64, generatedBy uint64) (*GeneratedReport, *common.AppError) {
172		saved, err := s.repo.FindSavedReport(savedReportID)
173		if err != nil {
174			return nil, common.NewNotFoundError("SavedReport")
175		}
176	
177		// Decode filters stored in the saved report.
178		var filters AnalyticsFilters
179		if len(saved.Filters) > 0 {
180			_ = json.Unmarshal(saved.Filters, &filters) // best-effort
181		}
182	
183		gen, appErr := s.ExportCSV(saved.ReportType, filters, generatedBy, "scheduled-report")
184		if appErr != nil {
185			return nil, appErr
186		}
187		gen.SavedReportID = &savedReportID
188	
189		// Update last generated timestamp.
190		now := time.Now().UTC()
191		saved.LastGeneratedAt = &now
192		_ = s.repo.UpdateSavedReport(saved)
193	
194		// Persist the link between saved and generated report.
195		if err := s.repo.UpdateSavedReport(saved); err != nil {
196			// Non-fatal — we already have the generated report.
197		}
198	
199		return gen, nil
200	}
