202	// ExportCSV runs a query for the given reportType and writes the result to a CSV
203	// file under storageRoot/reports/<uuid>.csv. Returns the GeneratedReport record.
204	func (s *Service) ExportCSV(reportType string, filters AnalyticsFilters, generatedBy uint64, purpose string) (*GeneratedReport, *common.AppError) {
205		dir, err := s.reportsDir()
206		if err != nil {
207			return nil, common.NewInternalError("storage not available")
208		}
209	
210		id := uuid.New().String()
211		filename := fmt.Sprintf("%s-%s.csv", reportType, id)
212		fullPath := filepath.Join(dir, filename)
213	
214		f, err := os.Create(fullPath)
215		if err != nil {
216			return nil, common.NewInternalError("failed to create report file")
217		}
218		defer f.Close()
219	
220		var count int
221		var writeErr error
222	
223		switch reportType {
224		case "work_orders":
225			count, writeErr = WriteWorkOrdersCSV(f, s.repo.db, filters)
226		case "payments":
227			count, writeErr = WritePaymentsCSV(f, s.repo.db, filters)
228		case "audit_logs":
229			count, writeErr = WriteAuditLogsCSV(f, s.repo.db, filters)
230		default:
231			_ = os.Remove(fullPath)
232			return nil, common.NewBadRequestError(fmt.Sprintf("unsupported export type: %s", reportType))
233		}
234	
235		if writeErr != nil {
236			_ = os.Remove(fullPath)
237			return nil, common.NewInternalError("failed to write CSV")
238		}
239	
240		info, err := f.Stat()
241		if err != nil {
242			return nil, common.NewInternalError("failed to stat report file")
243		}
244	
245		paramsJSON, _ := json.Marshal(map[string]interface{}{
246			"filters": filters,
247			"purpose": purpose,
248		})
249	
250		gen := &GeneratedReport{
251			UUID:        id,
252			ReportType:  reportType,
253			Format:      "CSV",
254			StoragePath: fullPath,
255			FileSize:    uint64(info.Size()),
256			RecordCount: count,
257			Parameters:  paramsJSON,
258			GeneratedBy: generatedBy,
259			GeneratedAt: time.Now().UTC(),
260		}
261	
262		if err := s.repo.CreateGeneratedReport(gen); err != nil {
263			return nil, common.NewInternalError("failed to persist generated report record")
264		}
265		return gen, nil
266	}
