74	// RetentionMetrics returns repeat-request counts for 30-day and 90-day windows.
75	func (r *Repository) RetentionMetrics(filters AnalyticsFilters) (*RetentionMetric, error) {
76		type unitCount struct {
77			UnitID *uint64
78			Count  int64
79		}
80	
81		retentionForDays := func(days int) (unique int64, repeat int64, err error) {
82			var rows []unitCount
83	
84			q := r.db.Table("work_orders").
85				Select("unit_id, COUNT(*) as count").
86				Where("deleted_at IS NULL AND unit_id IS NOT NULL")
87	
88			if !filters.From.IsZero() {
89				q = q.Where("created_at >= ?", filters.From)
90			} else {
91				q = q.Where("created_at >= DATE_SUB(NOW(), INTERVAL ? DAY)", days)
92			}
93			if !filters.To.IsZero() {
94				q = q.Where("created_at <= ?", filters.To)
95			}
96			if filters.PropertyID != nil {
97				q = q.Where("property_id = ?", *filters.PropertyID)
98			}
99	
100			q = q.Group("unit_id")
101	
102			if err = q.Scan(&rows).Error; err != nil {
103				return 0, 0, err
104			}
105	
106			for _, row := range rows {
107				unique++
108				if row.Count > 1 {
109					repeat++
110				}
111			}
112			return unique, repeat, nil
113		}
114	
115		unique30, repeat30, err := retentionForDays(30)
116		if err != nil {
117			return nil, err
118		}
119		unique90, repeat90, err := retentionForDays(90)
120		if err != nil {
121			return nil, err
122		}
123	
124		m := &RetentionMetric{
125			UniqueUnits30d: unique30,
126			RepeatUnits30d: repeat30,
127			UniqueUnits90d: unique90,
128			RepeatUnits90d: repeat90,
129		}
130		if unique30 > 0 {
131			m.RepeatRate30d = float64(repeat30) / float64(unique30)
132		}
133		if unique90 > 0 {
134			m.RepeatRate90d = float64(repeat90) / float64(unique90)
135		}
136		return m, nil
137	}
