139	// TagAnalysis returns the most-used tags across work orders.
140	// It combines skill_tag (plain column) with individual terms from the JSON tags array.
141	func (r *Repository) TagAnalysis(filters AnalyticsFilters) ([]TagMetric, error) {
142		// --- skill_tag column ---
143		q := r.db.Table("work_orders").
144			Select("skill_tag as tag, COUNT(*) as count").
145			Where("deleted_at IS NULL AND skill_tag != ''")
146		q = applyWorkOrderFilters(q, filters)
147		q = q.Group("skill_tag").Order("count DESC").Limit(50)
148	
149		var skillTagResults []TagMetric
150		if err := q.Scan(&skillTagResults).Error; err != nil {
151			return nil, err
152		}
153	
154		// --- JSON tags array (MySQL 8.0+ JSON_TABLE) ---
155		// Build WHERE clause and args matching applyWorkOrderFilters.
156		whereClause := "work_orders.deleted_at IS NULL AND work_orders.tags IS NOT NULL AND JSON_LENGTH(work_orders.tags) > 0"
157		jsonArgs := []interface{}{}
158		if filters.PropertyID != nil {
159			whereClause += " AND work_orders.property_id = ?"
160			jsonArgs = append(jsonArgs, *filters.PropertyID)
161		}
162		if !filters.From.IsZero() {
163			whereClause += " AND work_orders.created_at >= ?"
164			jsonArgs = append(jsonArgs, filters.From)
165		}
166		if !filters.To.IsZero() {
167			whereClause += " AND work_orders.created_at <= ?"
168			jsonArgs = append(jsonArgs, filters.To)
169		}
170	
171		jsonTagSQL := `
172			SELECT jt.tag, COUNT(*) as count
173			FROM work_orders, JSON_TABLE(work_orders.tags, '$[*]' COLUMNS(tag VARCHAR(255) PATH '$')) jt
174			WHERE ` + whereClause + `
175			GROUP BY jt.tag
176			ORDER BY count DESC
177			LIMIT 50`
178	
179		var jsonTagResults []TagMetric
180		if err := r.db.Raw(jsonTagSQL, jsonArgs...).Scan(&jsonTagResults).Error; err != nil {
181			// JSON_TABLE requires MySQL 8.0+; log and fall back to skill_tag results only.
182			log.Printf("WARN analytics: JSON tag analysis skipped (requires MySQL 8.0+): %v", err)
183			return skillTagResults, nil
184		}
185	
186		// Merge both sources, summing counts for tags that appear in both.
187		counts := make(map[string]int64, len(skillTagResults)+len(jsonTagResults))
188		for _, m := range skillTagResults {
189			counts[m.Tag] += m.Count
190		}
191		for _, m := range jsonTagResults {
192			if m.Tag != "" {
193				counts[m.Tag] += m.Count
194			}
195		}
196	
197		merged := make([]TagMetric, 0, len(counts))
198		for tag, count := range counts {
199			merged = append(merged, TagMetric{Tag: tag, Count: count})
200		}
201		sort.Slice(merged, func(i, j int) bool {
202			return merged[i].Count > merged[j].Count
203		})
204		if len(merged) > 50 {
205			merged = merged[:50]
206		}
207		return merged, nil
208	}
