210	// QualityMetrics returns aggregated rating and reporting quality data.
211	func (r *Repository) QualityMetrics(filters AnalyticsFilters) (*QualityMetric, error) {
212		type ratingAgg struct {
213			TotalRated    int64
214			AvgRating     float64
215			NegativeCount int64
216		}
217	
218		var agg ratingAgg
219		q := r.db.Table("work_orders").
220			Select("COUNT(rating) as total_rated, AVG(rating) as avg_rating, SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as negative_count").
221			Where("deleted_at IS NULL AND rating IS NOT NULL")
222	
223		q = applyWorkOrderFilters(q, filters)
224	
225		if err := q.Scan(&agg).Error; err != nil {
226			return nil, err
227		}
228	
229		// Count governance reports linked to work orders.
230		var reportedCount int64
231		rq := r.db.Table("reports").
232			Where("target_type = 'WorkOrder'")
233		if filters.PropertyID != nil {
234			rq = rq.Where("EXISTS (SELECT 1 FROM work_orders wo WHERE wo.id = reports.target_id AND wo.property_id = ?)", *filters.PropertyID)
235		}
236		_ = rq.Count(&reportedCount).Error // best-effort
237	
238		m := &QualityMetric{
239			TotalRated:    agg.TotalRated,
240			AverageRating: agg.AvgRating,
241			NegativeCount: agg.NegativeCount,
242			ReportedCount: reportedCount,
243		}
244		if agg.TotalRated > 0 {
245			m.NegativeRate = float64(agg.NegativeCount) / float64(agg.TotalRated)
246		}
247		return m, nil
248	}
