240	// authenticated user has created for the given action in the last hour and
241	// returns 429 if the max is reached.
242	func (m *Middleware) RateLimit(action string) gin.HandlerFunc {
243		return func(c *gin.Context) {
244			userIDVal, exists := c.Get(string(common.CtxKeyUserID))
245			if !exists {
246				c.Next()
247				return
248			}
249	
250			userID, ok := userIDVal.(uint64)
251			if !ok {
252				c.Next()
253				return
254			}
255	
256			maxPerHour := m.cfg.RateLimit.MaxSubmissionsPerHour
257	
258			// First check if there's a custom rate limit from enforcement actions
259			var customLimit struct {
260				RateLimitMax int
261			}
262			err := m.db.Table("enforcement_actions").
263				Select("rate_limit_max").
264				Where("user_id = ? AND action_type = ? AND is_active = ? AND (ends_at IS NULL OR ends_at > ?) AND revoked_at IS NULL",
265					userID, common.EnforcementRateLimit, true, time.Now().UTC()).
266				Order("rate_limit_max ASC").
267				Limit(1).
268				Scan(&customLimit).Error
269			if err == nil && customLimit.RateLimitMax > 0 {
270				maxPerHour = customLimit.RateLimitMax
271			}
272	
273			oneHourAgo := time.Now().UTC().Add(-1 * time.Hour)
274	
275			var count int64
276			err = m.db.Table("audit_logs").
277				Where("actor_id = ? AND action = ? AND created_at > ?", userID, action, oneHourAgo).
278				Count(&count).Error
279			if err != nil {
280				log.Printf("WARN RateLimit: failed to count actions: %v", err)
281				c.Next()
282				return
283			}
284	
285			if count >= int64(maxPerHour) {
286				common.RespondError(c, common.NewRateLimitError())
287				c.Abort()
288				return
289			}
290	
291			c.Next()
292		}
293	}
294	
295	// LocalNetworkOnly restricts access to requests originating from the specified
296	// CIDR ranges. Returns 403 for requests from disallowed IPs.
297	func (m *Middleware) LocalNetworkOnly(allowedCIDRs []string) gin.HandlerFunc {
298		// Parse CIDRs at middleware creation time
