543	// authorizeTransition checks if the current user is allowed to perform the transition.
544	func (h *Handler) authorizeTransition(c *gin.Context, wo *WorkOrder, toStatus string, userID uint64, roles []string) *common.AppError {
545		_ = c // included for consistency; roles/userID already extracted
546	
547		// SystemAdmin can do anything.
548		if hasRole(roles, common.RoleSystemAdmin) {
549			return nil
550		}
551	
552		// PropertyManager can perform manager-owned transitions only, and only for
553		// work orders on properties they manage:
554		//   New → Assigned            (dispatch/assignment)
555		//   AwaitingApproval → Completed   (approval)
556		//   AwaitingApproval → InProgress  (rejection/send-back)
557		//   Completed → Archived
558		// Technician-only transitions (Assigned→InProgress, InProgress→AwaitingApproval)
559		// are explicitly excluded.
560		if hasRole(roles, common.RolePropertyManager) {
561			managed, err := h.service.IsManagedBy(wo.PropertyID, userID)
562			if err != nil || !managed {
563				return common.NewForbiddenError("you do not manage the property for this work order")
564			}
565			pmAllowed := map[string]map[string]bool{
566				common.WOStatusNew:              {common.WOStatusAssigned: true},
567				common.WOStatusAwaitingApproval: {common.WOStatusCompleted: true, common.WOStatusInProgress: true},
568				common.WOStatusCompleted:        {common.WOStatusArchived: true},
569			}
570			if targets, ok := pmAllowed[wo.Status]; ok && targets[toStatus] {
571				return nil
572			}
573			return common.NewForbiddenError("property managers cannot perform this transition")
574		}
575	
576		// Technician can transition their own assigned work orders (Assigned->InProgress, InProgress->AwaitingApproval).
577		if hasRole(roles, common.RoleTechnician) {
578			if wo.AssignedTo == nil || *wo.AssignedTo != userID {
579				return common.NewForbiddenError("you can only transition work orders assigned to you")
580			}
581			if toStatus == common.WOStatusInProgress || toStatus == common.WOStatusAwaitingApproval {
582				return nil
583			}
584			return common.NewForbiddenError("technicians can only move to InProgress or AwaitingApproval")
585		}
586	
587		return common.NewForbiddenError("insufficient permissions for this transition")
588	}
