92	// parseDailyCron parses a 5-field cron expression of the form "M H * * *"
93	// (minute, hour, any day-of-month, any month, any weekday) and returns
94	// the UTC hour and minute at which the job should fire each day.
95	// Returns -1, -1 if the expression cannot be parsed or uses unsupported fields.
96	func parseDailyCron(expr string) (hour, minute int) {
97		fields := strings.Fields(expr)
98		if len(fields) != 5 {
99			return -1, -1
100		}
101		m, err1 := strconv.Atoi(fields[0])
102		h, err2 := strconv.Atoi(fields[1])
103		if err1 != nil || err2 != nil {
104			return -1, -1
105		}
106		if m < 0 || m > 59 || h < 0 || h > 23 {
107			return -1, -1
108		}
109		// Only support the wildcard form (* * *) for the remaining fields.
110		if fields[2] != "*" || fields[3] != "*" || fields[4] != "*" {
111			return -1, -1
112		}
113		return h, m
114	}
115	
116	// runCronScheduler fires job once per day at the time specified by cronExpr
117	// ("M H * * *" UTC). If the expression is invalid it falls back to a 24-hour
118	// fixed interval so the backup always runs even with a misconfigured cron.
119	func runCronScheduler(ctx context.Context, cronExpr string, job func()) {
120		h, m := parseDailyCron(cronExpr)
121		if h < 0 {
122			log.Printf("Scheduler [daily-backup]: cannot parse cron %q, falling back to 24h interval", cronExpr)
123			runScheduler(ctx, "daily-backup", 24*time.Hour, job)
124			return
125		}
126	
127		log.Printf("Scheduler [daily-backup] started with cron %q (daily at %02d:%02d UTC)", cronExpr, h, m)
128		for {
129			now := time.Now().UTC()
130			next := time.Date(now.Year(), now.Month(), now.Day(), h, m, 0, 0, time.UTC)
131			if !next.After(now) {
132				next = next.Add(24 * time.Hour)
133			}
134	
135			select {
136			case <-ctx.Done():
137				log.Printf("Scheduler [daily-backup] stopped")
138				return
139			case <-time.After(time.Until(next)):
140				func() {
141					defer func() {
142						if r := recover(); r != nil {
143							log.Printf("Scheduler [daily-backup] panic recovered: %v", r)
144						}
145					}()
146					job()
147				}()
148			}
149		}
150	}
